void control_fan(float temperature) {
    int fan_speed = 0;

    if (temperature < TEMP_THRESHOLD_LOW) {
        fan_speed = 0;
    } else if (temperature < TEMP_THRESHOLD_HIGH) {
        fan_speed = (int)((temperature - TEMP_THRESHOLD_LOW) / (TEMP_THRESHOLD_HIGH - TEMP_THRESHOLD_LOW) * 100);
