#define FAN_PIN 18
#define CS_MAX31855 7
#define MOSI_MAX31855 19
#define MISO_MAX31855 21
#define SCK_MAX31855 20

#define FAN_MIN 20
#define FAN_MAX 100
#define TEMP_THRESHOLD 30

struct max31855 {
    int cs;
    int spi_fd;
};

struct max31855 max31855;

void init_max31855() {
    max31855.cs = wiringPiSPISetup(0, 1000000);
    if (max31855.cs < 0) {
        fprintf(stderr, "Unable to set up SPI\n");
        exit(1);
    }
}

int read_max31855() {
    unsigned char buf[3];
    int ret;

    ret = spiWriteRead(max31855.spi_fd, (char*) &buf, 3, CS_MAX31855);
    if (ret != 3) {
        fprintf(stderr, "Error reading from MAX31855\n");
        return -1;
    }

    // Check for communication errors
    if ((buf[0] & 0x01) == 0x01) {
        fprintf(stderr, "Communication error with MAX31855\n");
        return -1;
    }

    return ((buf[1] << 8) | buf[2]);
}

int main() {
    int fan_pwm;
    float temp;
    FILE *log_file;
    int spi_fd;

    wiringPiSetup();
    pinMode(FAN_PIN, OUTPUT);

    init_max31855();
    max31855.spi_fd = spiOpen(0, SPI_MODE_0, 8, 0);
    if (max31855.spi_fd < 0) {
        fprintf(stderr, "Unable to open SPI device\n");
        exit(1);
    }

    log_file = fopen("fan_log.txt", "w");
    if (log_file == NULL) {
        fprintf(stderr, "Unable to open fan_log.txt\n");
        exit(1);
    }

    while (1) {
        temp = (float) read_max31855() / 16.0;
        fprintf(log_file, "%f,%d\n", temp, fan_pwm);

        if (temp > TEMP_THRESHOLD) {
            fan_pwm = map(temp - TEMP_THRESHOLD, 0, TEMP_THRESHOLD, FAN_MIN, FAN_MAX);
            pwmWrite(FAN_PIN, fan_pwm);
        } else {
            pwmWrite(FAN_PIN, FAN_MIN);
        }

        sleep(1);
    }

    fclose(log_file);
    close(max31855.spi_fd);
    spiClose(max31855.spi_fd);

    return 0;
}

float map(float x, float in_min, float in_max, float out_min, float out_max) {
    return (x - in_min) * (out_max - out_min) / (in_max - in_min) + out_min;
}

