void set_buzzer_frequency(int pin, int freq) {
    gpioSetMode(pin, PI_OUTPUT);
    gpioPWM(pin, freq);
}

void buzz(int pin, int freq) {
    gpioWrite(pin, 1);
    usleep(BUZZ_DURATION * 1000);
    gpioWrite(pin, 0);
    usleep(BUZZ_PAUSE * 1000);
}

void play_alarm(int pin1, int pin2) {
    set_buzzer_frequency(pin1, 1000 + FREQ_INCREMENT);
    set_buzzer_frequency(pin2, 1200 + FREQ_INCREMENT);

    buzz(pin1, 1000 + FREQ_INCREMENT);
    buzz(pin2, 1200 + FREQ_INCREMENT);
}

