#define DISTANCE_RANGE_HIGH 10
#define DISTANCE_RANGE_HIGH_FREQ 880

// Function to initialize the pigpio library
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }
    return 0;
}

// Function to set the GPIO pin as an output
int set_gpio_output(int gpio_pin) {
    if (gpioSetMode(gpio_pin, PI_OUTPUT) != 0) {
        fprintf(stderr, "Failed to set GPIO %d as output\n", gpio_pin);
        return -1;
    }
    return 0;
}

// Function to generate a PWM signal on the specified GPIO pin
int generate_pwm_signal(int gpio_pin, int frequency) {
    if (gpioSetPWMfrequency(gpio_pin, frequency) != 0) {
        fprintf(stderr, "Failed to set PWM frequency on GPIO %d\n", gpio_pin);
        return -1;
    }
    if (gpioPWM(gpio_pin, 128) != 0) { // 50% duty cycle (128/255)
        fprintf(stderr, "Failed to set PWM duty cycle on GPIO %d\n", gpio_pin);
        return -1;
    }
    return 0;
}

// Function to read the distance from stdin
int read_distance() {
    char buffer[10];
    if (fgets(buffer, sizeof(buffer), stdin) == NULL) {
        fprintf(stderr, "Error reading from stdin\n");
        return -1;
    }

    char *endptr;
    long distance = strtol(buffer, &endptr, 10);

    if (*endptr != '\0' || distance < 0 || distance > 100) {
        fprintf(stderr, "Invalid distance input: %s\n", buffer);
        return -1;
    }

    return (int)distance;
}

// Function to map the distance to a PWM frequency
int map_distance_to_frequency(int distance) {
    if (distance >= DISTANCE_RANGE_HIGH) {
        return DISTANCE_RANGE_HIGH_FREQ;
    } else if (distance >= DISTANCE_RANGE_LOW) {
        return DISTANCE_RANGE_LOW_FREQ;
    } else {
        return 0; // No buzzer
    }
}

int main() {
    // Initialize the pigpio library
    if (initialize_gpio() != 0) {
        return 1;
    }

    // Set GPIO pins as outputs
    if (set_gpio_output(BUZZER1_GPIO) != 0) {
        gpioTerminate();
        return 1;
    }
    if (set_gpio_output(BUZZER2_GPIO) != 0) {
        gpioTerminate();
        return 1;
    }

    // Main loop
    while (1) {
        int distance = read_distance();
        if (distance == -1) {
            continue; // Skip to the next iteration if there's an error
        }

        int frequency = map_distance_to_frequency(distance);

        // Generate PWM signals for both buzzers
        if (generate_pwm_signal(BUZZER1_GPIO, frequency) != 0) {
            gpioTerminate();
            return 1;
        }
        if (distance >= DISTANCE_RANGE_HIGH) {
            if (generate_pwm_signal(BUZZER2_GPIO, frequency) != 0) {
                gpioTerminate();
                return 1;
            }
        } else if (distance >= DISTANCE_RANGE_LOW) {
            if (generate_pwm_signal(BUZZER2_GPIO, frequency) != 0) {
                gpioTerminate();
                return 1;
            }
        } else {
            if (gpioWrite(BUZZER2_GPIO, 0) != 0) {
                gpioTerminate();
                return 1;
            }
        }

        printf("Distance: %d cm, Frequency: %d Hz\n", distance, frequency);
        gpioDelay(100); // Delay for 100 milliseconds
    }

    // Terminate the pigpio library
    gpioTerminate();

    return 0;
}

